  await page.route('**/api/workgroups', async (route) => {
    await route.fulfill({
      contentType: 'application/json',
      body: JSON.stringify([
        {
          id: 1,
          name: 'Demo',
          description: '',
          criticality: 'MEDIUM',
          userCount: 0,
          assetCount: 0,
          awsAccountsCount: 0,
          adDomainsCount: 0,
          createdAt: '2026-05-27T10:00:00Z',
          updatedAt: '2026-05-27T10:00:00Z',
        },
      ]),
    });
