                        // waiting and render their unauthorized state instead of
                        // hanging on the 5s timeout.
                        console.error('Auth status check failed:', response.statusText);
                        resolveAuth(null);
                        return;
                    }
                    const user = await response.json();
                    console.log('User authenticated:', user.username, 'Roles:', user.roles);
                    resolveAuth(user);
                } catch (error) {
                    // Network errors during navigation are expected; don't
                    // redirect, but do resolve so islands don't hang.
                    console.warn('Failed to fetch auth status:', error);
                    resolveAuth(null);
